  1→package csvutil
  2→
  3→import (
  4→	"strings"
  5→	"testing"
  6→)
  7→
  8→const csvData = `name,age,score,city
  9→Alice,30,9.5,New York
 10→Bob,25,8.1,
 11→Charlie,0,,Paris
 12→`
 13→
 14→const tsvData = "name\tage\tscore\n" +
 15→	"Alice\t30\t9.5\n" +
 16→	"Bob\t25\t8.1\n"
 17→
 18→const quotedCSV = `name,description,value
 19→Alice,"tall, blonde, and smart",42
 20→Bob,"says ""hello"" often",7
 21→Carol,"line1
 22→line2",99
 23→`
 24→
 25→const headerOnlyCSV = "name,age,score\n"
 26→
 27→func mustReader(t *testing.T, data string, opts ...Option) *Reader {
 28→	t.Helper()
 29→	r, err := NewReader(strings.NewReader(data), opts...)
 30→	if err != nil {
 31→		t.Fatalf("NewReader: %v", err)
 32→	}
 33→	return r
 34→}
 35→
 36→func collectRows(t *testing.T, r *Reader) []Row {
 37→	t.Helper()
 38→	var rows []Row
 39→	for {
 40→		row, ok, err := r.Next()
 41→		if err != nil {
 42→			t.Fatalf("Next: %v", err)
 43→		}
 44→		if !ok {
 45→			break
 46→		}
 47→		rows = append(rows, row)
 48→	}
 49→	return rows
 50→}
 51→
 52→// 1. Normal CSV parsing.
 53→func TestNormalCSV(t *testing.T) {
 54→	r := mustReader(t, csvData)
 55→	rows := collectRows(t, r)
 56→
 57→	if len(rows) != 3 {
 58→		t.Fatalf("want 3 rows, got %d", len(rows))
 59→	}
 60→
 61→	if got := rows[0].String("name"); got != "Alice" {
 62→		t.Errorf("row[0] name: want Alice, got %q", got)
 63→	}
 64→	if got := rows[0].Int("age"); got != 30 {
 65→		t.Errorf("row[0] age: want 30, got %d", got)
 66→	}
 67→	if got := rows[0].Float("score"); got != 9.5 {
 68→		t.Errorf("row[0] score: want 9.5, got %f", got)
 69→	}
 70→	if got := rows[1].String("name"); got != "Bob" {
 71→		t.Errorf("row[1] name: want Bob, got %q", got)
 72→	}
 73→}
 74→
 75→// 2. TSV parsing via WithDelimiter.
 76→func TestTSV(t *testing.T) {
 77→	r := mustReader(t, tsvData, WithDelimiter('\t'))
 78→	rows := collectRows(t, r)
 79→
 80→	if len(rows) != 2 {
 81→		t.Fatalf("want 2 rows, got %d", len(rows))
 82→	}
 83→	if got := rows[0].String("name"); got != "Alice" {
 84→		t.Errorf("row[0] name: want Alice, got %q", got)
 85→	}
 86→	if got := rows[0].Int("age"); got != 30 {
 87→		t.Errorf("row[0] age: want 30, got %d", got)
 88→	}
 89→	if got := rows[1].Float("score"); got != 8.1 {
 90→		t.Errorf("row[1] score: want 8.1, got %f", got)
 91→	}
 92→}
 93→
 94→// 3. Missing columns return zero/nil.
 95→func TestMissingColumn(t *testing.T) {
 96→	r := mustReader(t, csvData)
 97→	rows := collectRows(t, r)
 98→
 99→	row := rows[0]
100→
101→	if got := row.String("nonexistent"); got != "" {
102→		t.Errorf("missing String: want empty, got %q", got)
103→	}
104→	if got := row.Int("nonexistent"); got != 0 {
105→		t.Errorf("missing Int: want 0, got %d", got)
106→	}
107→	if got := row.Float("nonexistent"); got != 0 {
108→		t.Errorf("missing Float: want 0, got %f", got)
109→	}
110→	if got := row.OptionalString("nonexistent"); got != nil {
111→		t.Errorf("missing OptionalString: want nil, got %v", got)
112→	}
113→	if got := row.OptionalInt("nonexistent"); got != nil {
114→		t.Errorf("missing OptionalInt: want nil, got %v", got)
115→	}
116→	if got := row.OptionalFloat("nonexistent"); got != nil {
117→		t.Errorf("missing OptionalFloat: want nil, got %v", got)
118→	}
119→}
120→
121→// 4. Type coercion — Int and Float parse correctly.
122→func TestTypeCoercion(t *testing.T) {
123→	r := mustReader(t, csvData)
124→	rows := collectRows(t, r)
125→
126→	// row[0]: age=30, score=9.5
127→	if got := rows[0].Int("age"); got != 30 {
128→		t.Errorf("Int coercion: want 30, got %d", got)
129→	}
130→	if got := rows[0].Float("score"); got != 9.5 {
131→		t.Errorf("Float coercion: want 9.5, got %f", got)
132→	}
133→	// row[2]: age=0 (explicit zero), score="" (empty → 0)
134→	if got := rows[2].Int("age"); got != 0 {
135→		t.Errorf("Int zero: want 0, got %d", got)
136→	}
137→	if got := rows[2].Float("score"); got != 0 {
138→		t.Errorf("Float empty: want 0, got %f", got)
139→	}
140→}
141→
142→// 5. Quoted values with embedded commas and newlines.
143→func TestQuotedValues(t *testing.T) {
144→	r := mustReader(t, quotedCSV)
145→	rows := collectRows(t, r)
146→
147→	if len(rows) != 3 {
148→		t.Fatalf("want 3 rows, got %d", len(rows))
149→	}
150→	if got := rows[0].String("description"); got != "tall, blonde, and smart" {
151→		t.Errorf("quoted comma: got %q", got)
152→	}
153→	if got := rows[1].String("description"); got != `says "hello" often` {
154→		t.Errorf("quoted double-quote: got %q", got)
155→	}
156→	if got := rows[2].String("description"); got != "line1\nline2" {
157→		t.Errorf("quoted newline: got %q", got)
158→	}
159→}
160→
161→// 6. LazyQuotes handles malformed (bare) quotes.
162→func TestLazyQuotes(t *testing.T) {
163→	data := "name,note\nAlice,she said \"hello\"\nBob,fine\n"
164→	r := mustReader(t, data, WithLazyQuotes(true))
165→	rows := collectRows(t, r)
166→
167→	if len(rows) != 2 {
168→		t.Fatalf("want 2 rows, got %d", len(rows))
169→	}
170→	if got := rows[0].String("name"); got != "Alice" {
171→		t.Errorf("lazy quote row name: got %q", got)
172→	}
173→}
174→
175→// 7. Optional accessors return nil for empty cells and missing columns.
176→func TestOptionalEmptyFields(t *testing.T) {
177→	r := mustReader(t, csvData)
178→	rows := collectRows(t, r)
179→
180→	// row[1]: city="" (empty)
181→	if got := rows[1].OptionalString("city"); got != nil {
182→		t.Errorf("empty OptionalString: want nil, got %v", *got)
183→	}
184→	// row[2]: score="" (empty)
185→	if got := rows[2].OptionalFloat("score"); got != nil {
186→		t.Errorf("empty OptionalFloat: want nil, got %v", *got)
187→	}
188→	// Non-empty value should not be nil.
189→	if got := rows[0].OptionalString("name"); got == nil || *got != "Alice" {
190→		t.Errorf("non-empty OptionalString: want Alice, got %v", got)
191→	}
192→	if got := rows[0].OptionalInt("age"); got == nil || *got != 30 {
193→		t.Errorf("non-empty OptionalInt: want 30, got %v", got)
194→	}
195→	if got := rows[0].OptionalFloat("score"); got == nil || *got != 9.5 {
196→		t.Errorf("non-empty OptionalFloat: want 9.5, got %v", got)
197→	}
198→}
199→
200→// 8. EOF: Next returns false, nil at end of file.
201→func TestEOF(t *testing.T) {
202→	const single = "name,age\nAlice,30\n"
203→	r := mustReader(t, single)
204→
205→	_, ok, err := r.Next()
206→	if err != nil || !ok {
207→		t.Fatalf("first Next: ok=%v err=%v", ok, err)
208→	}
209→	_, ok, err = r.Next()
210→	if err != nil {
211→		t.Fatalf("EOF Next returned error: %v", err)
212→	}
213→	if ok {
214→		t.Error("EOF Next: want ok=false")
215→	}
216→}
217→
218→// 9. Header-only file: Next immediately returns false.
219→func TestHeaderOnly(t *testing.T) {
220→	r := mustReader(t, headerOnlyCSV)
221→	_, ok, err := r.Next()
222→	if err != nil {
223→		t.Fatalf("header-only Next: %v", err)
224→	}
225→	if ok {
226→		t.Error("header-only: want ok=false on first Next")
227→	}
228→}
229→
230→// 10. NewReader returns error on bad header read.
231→func TestNewReaderError(t *testing.T) {
232→	// An empty reader has no header line → should error.
233→	_, err := NewReader(strings.NewReader(""))
234→	if err == nil {
235→		t.Error("empty input: want error from NewReader, got nil")
236→	}
237→}
