 11→// newTestMatcher builds a Matcher without a database for unit testing.
 12→func newTestMatcher() *Matcher {
 13→	return &Matcher{
 14→		exact: map[string]string{
 15→			"harvard university":                        "166027",
 16→			"arizona state university-tempe":            "104151",
 17→			"ohio state university-main campus":         "204796",
 18→			"purdue university-main campus":             "243780",
 19→			"university of michigan-ann arbor":          "170976",
 20→			"university of illinois urbana-champaign":   "145637",
 21→		},
 22→		normalized: map[string]string{
 23→			"harvard university":                        "166027",
 24→			"arizona state university tempe":            "104151",
 25→			"ohio state university main campus":         "204796",
 26→			"purdue university main campus":             "243780",
 27→			"university of michigan ann arbor":          "170976",
 28→			"university of illinois urbana champaign":   "145637",
 29→			// Extra normalized variant for St. John's
 30→			"st johns university":                       "194091",
 31→		},
 32→		alias: map[string]string{
 33→			"harvard":        "166027",
 34→			"the ohio state": "204796",
 35→		},
 36→		ope6: map[string]string{
 37→			"001082": "166027",
 38→			"001083": "104151",
 39→		},
