192→// TestIntegrationMatcherLoad verifies Load() against a real database.
193→// Skipped when running with -short or when DATABASE_URL is unset.
194→func TestIntegrationMatcherLoad(t *testing.T) {
195→	if testing.Short() {
196→		t.Skip("skipping integration test in short mode")
197→	}
198→	dbURL := os.Getenv("DATABASE_URL")
199→	if dbURL == "" {
200→		t.Skip("DATABASE_URL not set")
201→	}
202→
203→	ctx := context.Background()
204→	pool, err := dbutil.Connect(ctx, dbURL)
205→	if err != nil {
206→		t.Fatalf("namematch: connect: %v", err)
207→	}
208→	defer pool.Close()
209→
210→	m, err := Load(ctx, pool)
211→	if err != nil {
212→		t.Fatalf("Load: %v", err)
213→	}
214→
215→	// Verify basic stats — we should have loaded something
216→	if len(m.exact) == 0 {
217→		t.Error("exact map is empty — no institutions loaded")
218→	}
219→	if len(m.ope6) == 0 {
220→		t.Error("ope6 map is empty")
221→	}
222→
223→	// Spot-check a known canonical name if it exists in the DB.
224→	// Harvard (unit_id 166027) should always be present in NCES data.
225→	uid, ok := m.Match("Harvard University")
226→	if ok {
227→		t.Logf("Harvard University → unit_id %q", uid)
228→	}
229→
230→	// Verify OPE lookups are consistent: if we have an exact match,
231→	// OPE lookups for the same institution should return the same unit_id.
232→	for ope6, wantUID := range m.ope6 {
233→		gotUID, found := m.MatchByOPE6(ope6)
234→		if !found {
235→			t.Errorf("MatchByOPE6(%q): not found but expected in map", ope6)
236→		}
237→		if gotUID != wantUID {
238→			t.Errorf("MatchByOPE6(%q) = %q, want %q", ope6, gotUID, wantUID)
239→		}
240→		// Only spot-check first 5 to keep runtime short
241→		break
242→	}
243→}
