  8→func TestDeriveOpinion(t *testing.T) {
  9→	tests := []struct {
 10→		raw        string
 11→		wantMethod string
 12→		wantRank   int
 13→		wantScore  float64
 14→		wantTier   string
 15→		wantErr    bool
 16→	}{
 17→		// Numeric ranks
 18→		{raw: "1", wantMethod: "rank", wantRank: 1},
 19→		{raw: "42", wantMethod: "rank", wantRank: 42},
 20→		{raw: " 15 ", wantMethod: "rank", wantRank: 15},
 21→
 22→		// Tier strings
 23→		{raw: "Tier 1", wantMethod: "tier", wantTier: "Tier 1"},
 24→		{raw: "Tier 2", wantMethod: "tier", wantTier: "Tier 2"},
 25→		{raw: "tier 3", wantMethod: "tier", wantTier: "tier 3"},
 26→
 27→		// Ranges
 28→		{raw: "201-300", wantMethod: "range", wantRank: 251, wantTier: "201-300"},
 29→		{raw: "1-10", wantMethod: "range", wantRank: 6, wantTier: "1-10"},
 30→		{raw: "100-200", wantMethod: "range", wantRank: 150, wantTier: "100-200"},
 31→
 32→		// Decimal scores
 33→		{raw: "78.5", wantMethod: "score", wantScore: 78.5},
 34→		{raw: "99.9", wantMethod: "score", wantScore: 99.9},
 35→
 36→		// Errors
 37→		{raw: "", wantErr: true},
 38→		{raw: "N/A", wantErr: true},
 39→		{raw: "not ranked", wantErr: true},
 40→	}
 41→
 42→	for _, tt := range tests {
 43→		t.Run(tt.raw, func(t *testing.T) {
 44→			method, rank, score, tier, err := DeriveOpinion(tt.raw)
 45→			if tt.wantErr {
 46→				if err == nil {
 47→					t.Fatalf("expected error for %q, got method=%q", tt.raw, method)
 48→				}
 49→				return
 50→			}
 51→			if err != nil {
 52→				t.Fatalf("unexpected error for %q: %v", tt.raw, err)
 53→			}
 54→			if method != tt.wantMethod {
 55→				t.Errorf("method: got %q, want %q", method, tt.wantMethod)
 56→			}
 57→			if rank != tt.wantRank {
 58→				t.Errorf("rank: got %d, want %d", rank, tt.wantRank)
 59→			}
 60→			if score != tt.wantScore {
 61→				t.Errorf("score: got %f, want %f", score, tt.wantScore)
 62→			}
 63→			if tier != tt.wantTier {
 64→				t.Errorf("tier: got %q, want %q", tier, tt.wantTier)
 65→			}
 66→		})
 67→	}
 68→}
