167→func contains(s, substr string) bool {
168→	return len(s) >= len(substr) && (s == substr || len(s) > 0 && stringContains(s, substr))
169→}
170→
171→func stringContains(s, substr string) bool {
172→	for i := 0; i <= len(s)-len(substr); i++ {
173→		if s[i:i+len(substr)] == substr {
174→			return true
175→		}
176→	}
177→	return false
178→}
