 34→		ExtractedAt:         "2026-08-15T14:30:00Z",
 35→		BigfutureID:         "1251",
 36→		BigfutureAgrees:     true,
 37→	}
 38→
 39→	raw, err := json.Marshal(original)
 40→	if err != nil {
 41→		t.Fatalf("marshal: %v", err)
 42→	}
 43→
 44→	var decoded DeadlineData
 45→	if err := json.Unmarshal(raw, &decoded); err != nil {
 46→		t.Fatalf("unmarshal: %v", err)
 47→	}
 48→
 49→	// Verify plan count
 50→	if len(decoded.Plans) != 2 {
 51→		t.Errorf("expected 2 plans, got %d", len(decoded.Plans))
 52→	}
