 24→func newMockBrowser(mappings map[string]mockResult) *mockBrowser {
 25→	m := &mockBrowser{}
 26→	for k, v := range mappings {
 27→		m.urlKeys = append(m.urlKeys, k)
 28→		m.calls = append(m.calls, v)
 29→	}
